from typing import List


class DSU:
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.rank = [0] * n
        self.count = n  # number of disjoint sets

    def find(self, x: int) -> int:
        # iterative path compression
        root = x
        while self.parent[root] != root:
            root = self.parent[root]
        while self.parent[x] != root:
            self.parent[x], x = root, self.parent[x]
        return root

    def union(self, a: int, b: int) -> bool:
        ra, rb = self.find(a), self.find(b)
        if ra == rb:
            return False  # already connected
        if self.rank[ra] < self.rank[rb]:
            ra, rb = rb, ra
        self.parent[rb] = ra
        if self.rank[ra] == self.rank[rb]:
            self.rank[ra] += 1
        self.count -= 1
        return True


class Solution:
    def countComponents(self, n: int, edges: List[List[int]]) -> int:
        if n <= 0:
            return 0
        dsu = DSU(n)
        for a, b in edges:
            dsu.union(a, b)
        return dsu.count


# ---- internal verification ----
def brute(n, edges):
    if n <= 0:
        return 0
    adj = {i: [] for i in range(n)}
    for a, b in edges:
        adj[a].append(b)
        adj[b].append(a)
    seen = set()
    comp = 0
    for i in range(n):
        if i not in seen:
            comp += 1
            stack = [i]
            while stack:
                node = stack.pop()
                if node in seen:
                    continue
                seen.add(node)
                stack.extend(adj[node])
    return comp


import random

s = Solution()
# sample cases
assert s.countComponents(5, [[0, 1], [1, 2], [3, 4]]) == 2
assert s.countComponents(4, [[0, 1], [2, 3], [1, 3]]) == 1
# edge cases
assert s.countComponents(1, []) == 1
assert s.countComponents(0, []) == 0
assert s.countComponents(3, []) == 3
assert s.countComponents(3, [[0, 0]]) == 3          # self-loop
assert s.countComponents(3, [[0, 1], [0, 1], [1, 0]]) == 2  # duplicates
# random oracle test against BFS brute force
for _ in range(3000):
    n = random.randint(1, 12)
    e = [[random.randint(0, n - 1), random.randint(0, n - 1)]
         for _ in range(random.randint(0, 15))]
    assert s.countComponents(n, [row[:] for row in e]) == brute(n, e), (n, e)
print("ALL PASS")
